export default {
  async fetch(request, env) {
    if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
    }

    const contentType = request.headers.get('content-type') || '';
    if (!contentType.includes('application/json')) {
      return new Response('Content-Type must be application/json', { status: 400 });
    }

    try {
      const { username, password } = await request.json();
      
      // Validate input
      if (!username || !password) {
        return new Response('Username and password required', { status: 400 });
      }

      // Sanitize input
      const sanitizedUsername = username.trim().toLowerCase();
      if (sanitizedUsername.length === 0 || sanitizedUsername.length > 50) {
        return new Response('Invalid username', { status: 400 });
      }

      // Get user from KV
      const userKey = `user:${sanitizedUsername}`;
      const userData = await env.USER_DB.get(userKey);
      
      if (!userData) {
        return new Response('Invalid credentials', { status: 401 });
      }

      const user = JSON.parse(userData);
      
      // Verify password (assuming hashed password in KV)
      const isValid = await verifyPassword(password, user.password_hash);
      if (!isValid) {
        return new Response('Invalid credentials', { status: 401 });
      }

      // Generate session token
      const sessionToken = generateToken();
      
      // Store session in KV with expiration
      const sessionKey = `session:${sessionToken}`;
      const sessionData = {
        username: sanitizedUsername,
        created: Date.now(),
        expires: Date.now() + (24 * 60 * 60 * 1000) // 24 hours
      };
      
      await env.SESSIONS.put(sessionKey, JSON.stringify(sessionData), {
        expirationTtl: 24 * 60 * 60
      });

      return new Response(JSON.stringify({ token: sessionToken }), {
        headers: { 'Content-Type': 'application/json' }
      });
    } catch (error) {
      return new Response('Internal Server Error', { status: 500 });
    }
  }
};

